    "css": "@media only screen and (max-width: 1199px) and (min-width: 992px)  {\n\t.rt-room--slider-style1 .item-inner .rt-details-info {\n\t  left: 15px;\n\t  right: 15px;\n\t  bottom: 10px;\n\t}\n\t.blog__item.if__is__small .blog__item__meta__title h5 {\n\t  \tfont-size: 20px;\n\t  \tline-height: 30px;\n\t}\n\t.blog__item__meta__cat {\n\t  \tmargin-bottom: 6px;\n\t}\n\t.rt-room--slider-style1 .item-inner {\n\t    height: 400px;\n\t}\n}\n\n@media only screen and (min-width: 992px) {\n\t.nav-menu-link.menu-button{\n\t\tdisplay: none;\n\t}\n\t.sidebarmenu-area .nav-menu-link.menu-button{\n\t\tdisplay: flex;\n\t\tgap: 8px;\n\t\talign-items: center;\n\t}\n}\n\n@media only screen and (max-width: 991px) {\n\tnav.nav.navbar{\n\t\tdisplay: none;\n\t}\n\t.nav-menu-link.menu-button{\n\t\tdisplay: flex;\n\t\tjustify-content: flex-end;\n\t}\n\t.menu-area-addon-offcan nav.nav.navbar{\n\t\tdisplay: block;\n\t}\n\t.rt-row-header{\n\t\tpadding: 8px 0;\n\t}\n\t.eshb-search .eshb-search-form .eshb-form-group .form-control{\n\t\tmax-width: 110px;\n\t}\n\t.testimonial__item__content{\n\t\tdisplay: block;\n\t}\n\t.rtmega-menu-area .mobile-menu-area .rtmega-menu-mobile-sidebar {\n\t  \tpadding: 46px 10px 50px 10px;\n\t}\n\t.padding-full-layout-right .contents-sticky {\n\t  \tpadding-right: 15px;\n\t}\n\t.resturant__menu__list .nav-tabs{\n\t\tflex-wrap: wrap;\n\t\tjustify-content: start;\n\t}\n}\n\n\n@media only screen and (max-width: 767px) {\n\t.react-heading-here .rt-title-here {\n\t  \tfont-size: 40px;\n\t  \tline-height: 45px;\n\t}\n\t.blog__item.if__is__small{\n\t\tdisplay: block;\n\t}\n\t.blog__item.if__is__small .blog__item__thumb {\n\t  margin-bottom: 30px;\n\t}\n\t.rt--testimonial--style3 .testimonial__item__content .slider__text {\n\t  \tpadding-right: 0;\n\t}\n\t.rt--testimonial--style3 .testimonial__item__content .author__icon {\n\t  \tmargin-bottom: 20px;\n\t}\n\t.rt-room--slider-style2 .item-inner {\n\t  \tpadding-bottom: 20px;\n\t}\n\t.testimonial__item__content .slider__text {\n\t  \tfont-size: 22px;\n\t  \tline-height: 34px;\n\t}\n\t.rt-room--slider-style1 .item-inner {\n\t  \theight: 400px;\n\t}\n\t.rt__en__befores.rt__en__befores_left::after {\n\t    right: 0;\n\t}\n\t.rt-user-meta-info {\n\t  gap: 10px;\n\t  flex-wrap: wrap;\n\t}\n\t.testimonial__item__content .author__icon img {\n\t    border-radius: 0;\n\t    margin-bottom: 30px;\n\t}\n\t.single__menu__item__list {\n\t  \tdisplay: block;\n\t}\n\t.single__menu__item__list .single__menu__item {\n\t  \tmax-width: 100%;\n\t  \tflex: 0 0 100%;\n\t}\n\t.single__menu__item__list .single__menu__item:nth-child(2n) {\n\t  \tpadding-left: 0;\n\t}\n}\n\n\n@media only screen and (max-width: 480px) {\n\t.blog .reactheme-blog .blog-item, .archive .reactheme-blog .blog-item {\n\t  \tpadding: 15px;\n\t}\n\t.single__menu__item__list .single__menu__item .menu__thumb {\n\t\tmax-width: 22%;\n\t\tflex: 0 0 22%;\n\t}\n\t.single__menu__item__list .single__menu__item .menu__meta {\n\t  \tflex: 0 0 78%;\n\t  \tmax-width: 78%;\n\t}\n\t.resturant__menu__list {\n\t  \tmargin-bottom: 36px;\n\t}\n}"
